#include <bits/stdc++.h>
using namespace std;

struct road {
    int to, len;
};

int n;
long long maxn, len;
vector<road> r[100005];

void DFS(int k, int last) {
    if (k != 1 && r[k].size() == 1) {
        maxn = max(maxn, len);
        return ;
    }
    for (road i : r[k]) {
        if (i.to == last) continue;
        len += i.len;
        DFS(i.to, k);
        len -= i.len;
    }
}

int main() {
    cin >> n;
    long long sum = 0;
    for (int i = 0; i < n - 1; i++) {
        int u, v, l;
        cin >> u >> v >> l;
        r[u].push_back({v, l});
        r[v].push_back({u, l});
        sum += 2 * l;
    }
    DFS(1, -1);
    cout << sum - maxn;
    return 0;
}

